```python
class Сlient:
    def __init__(self, name, balance=0):
        self.name = name
        self.balance = balance

class Bank:
    def __init__(self):
        self.clients = {}

    def add_client(self, client):
        self.clients[client.name] = client

    def get_client(self, name):
        return self.clients.get(name)

    def transfer_money(self, sender_name, receiver_name, amount):
        sender = self.get_client(sender_name)
        receiver = self.get_client(receiver_name)

        if sender and receiver:
            if sender.balance >= amount:
                sender.balance -= amount
                receiver.balance += amount
                print(f"Перевод на сумму {amount} на счет {receiver_name} выполнен.")
            else:
                print(f"На счете {sender_name} недостаточно средств.")
        else:
            print("Клиент не найден.")

    def show_balance(self, name):
        client = self.get_client(name)
        if client:
            print(f"Баланс на счете {name}: {client.balance}")
        else:
            print("Клиент не найден.")

# Создаем банк
bank = Bank()

# Создаем клиентов
client1 = Сlient("Иван Иванов", 1000)
client2 = Сlient("Петр Петров", 500)

# Добавляем клиентов в банк
bank.add_client(client1)
bank.add_client(client2)

# Показываем баланс клиентов
bank.show_balance("Иван Иванов")
bank.show_balance("Петр Петров")

