### Код программы

```python
import getpass
import hashlib
from cryptography.fernet import Fernet

class PasswordManager:
    def __init__(self):
        self.keys = {}

    def generate_key(self):
        """Сгенерировать ключ для шифрования"""
        return Fernet.generate_key()

    def encrypt_password(self, password, key):
        """Зашифровать пароль"""
        cipher_suite = Fernet(key)
        encrypted_password = cipher_suite.encrypt(password.encode())
        return encrypted_password

    def decrypt_password(self, encrypted_password, key):
        """Расшифровать пароль"""
        cipher_suite = Fernet(key)
        decrypted_password = cipher_suite.decrypt(encrypted_password).decode()
        return decrypted_password

    def save_password(self, username, password, key):
        """Сохранить пароль"""
        encrypted_password = self.encrypt_password(password, key)
        self.keys[username] = encrypted_password

    def load_password(self, username):
        """Загрузить пароль"""
        if username in self.keys:
            return self.decrypt_password(self.keys[username], self.generate_key())
        else:
            return None

